import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Chain of Thought — 2026-05-12","description":"","frontmatter":{"title":"Chain of Thought — 2026-05-12","date":"2026-05-12T00:00:00.000Z","source":"Chain of Thought","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-12-chain-of-thought.md","filePath":"research/ai-news/2026-05/2026-05-12-chain-of-thought.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-12-chain-of-thought.md"};function s(i,e,h,l,p,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="⛓️-chain-of-thought-—-2026-05-12" tabindex="-1">⛓️ Chain of Thought — 2026-05-12 <a class="header-anchor" href="#⛓️-chain-of-thought-—-2026-05-12" aria-label="Permalink to &quot;⛓️ Chain of Thought — 2026-05-12&quot;">​</a></h1><blockquote><p>Dan Shipper（Every.to）的 AI 與策略 / 社會交點深度週報 來源：<a href="https://every.to/chain-of-thought/feed.xml" target="_blank" rel="noreferrer">Chain of Thought</a></p></blockquote><hr><h2 id="inside-anthropic-s-2026-developer-conference" tabindex="-1"><a href="https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference" target="_blank" rel="noreferrer">Inside Anthropic’s 2026 Developer Conference</a> <a class="header-anchor" href="#inside-anthropic-s-2026-developer-conference" aria-label="Permalink to &quot;[Inside Anthropic’s 2026 Developer Conference](https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference)&quot;">​</a></h2><p><em>⛓️ Chain of Thought | 2026-05-07</em></p><h2 id="by-dan-shipper-marcus-moretti-and-katie-parrott" tabindex="-1">| | | by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>, <a href="https://every.to/@marcus_fd8302_1" target="_blank" rel="noreferrer">Marcus Moretti</a>, and <a href="https://every.to/@katie.parrott12" target="_blank" rel="noreferrer">Katie Parrott</a> <a class="header-anchor" href="#by-dan-shipper-marcus-moretti-and-katie-parrott" aria-label="Permalink to &quot;| | | by [Dan Shipper](https://every.to/@danshipper), [Marcus Moretti](https://every.to/@marcus_fd8302_1), and [Katie Parrott](https://every.to/@katie.parrott12)&quot;">​</a></h2><p>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a><br> Midjourney/Every illustration.</p><p><em>Was this newsletter forwarded to you?</em><a href="https://every.to/account" target="_blank" rel="noreferrer">Sign up</a>_ to get it in your inbox._</p><hr><p>To our surprise, the biggest launch from Anthropic’s <em><a href="https://claude.com/code-with-claude" target="_blank" rel="noreferrer">developer conference</a></em> in San Francisco yesterday wasn’t a model or a feature. Instead, it was the company’s announcement of <em><a href="https://www.anthropic.com/news/higher-limits-spacex" target="_blank" rel="noreferrer">a deal with SpaceX</a></em> to allocate all of the capacity in the latter’s Colossus supercluster to Claude.</p><p>Anthropic has been riding a historic demand surge over the last year as Claude Code opened up a new wave of agentic coding for engineers and non-engineers alike. But compute constraints have caused friction even amongst its most die-hard fans—we’ve written previously about <em><a href="https://every.to/context-window/get-your-hands-dirty#signal" target="_blank" rel="noreferrer">being frustrated</a></em> with its OpenClaw restrictions and the speed of its latest models like <em><a href="https://every.to/vibe-check/opus-4-7" target="_blank" rel="noreferrer">Opus 4.7</a></em>.</p><p>The deal with SpaceX changes that equation. Anthropic has already doubled rate limits for subscription plans, removed peak-hour limits on Pro and Max accounts, and raised API rate limits by as much as almost 17 times for certain tiers.</p><p>Other than that, the big story is Claude Managed Agents, Anthropic’s hosted agent product. The company released <em><a href="https://claude.com/blog/new-in-claude-managed-agents" target="_blank" rel="noreferrer">three new features</a></em> :</p><ol><li><strong>Multi-agent orchestration:</strong> a coordinator agent that spins up subagents in parallel baked into the platform</li><li><strong>Dreaming:</strong> Anthropic’s general-purpose version of <em><a href="https://every.to/guides/compound-engineering" target="_blank" rel="noreferrer">compound engineering</a></em> , a feature that allows agents to learn from past sessions to improve between runs</li><li><strong>Outcomes:</strong> Anthropic’s answer to Codex’s /goals command, allowing developers to specify an outcome and run an agent in a loop until the outcome is achieved</li></ol><p>By themselves, these features are nice but not groundbreaking. What’s more important is that <em>what an AI platform is</em> has changed. In the GPT-3 days, the platform was a text completion end-point: Send text in, get text out. Now, with Claude Managed Agents, the platform is an AI model with a harness and host computer—all provided with unlimited scaling by the model companies.</p><p><strong><a href="https://cora.computer" target="_blank" rel="noreferrer">Cora</a> <strong>general manager</strong><a href="https://every.to/@kieran_1355" target="_blank" rel="noreferrer">Kieran Klaassen</a></strong> and I reported live from conference with our biggest takeaways, including the xAI compute deal, doubled Claude usage limits, Claude Managed Agents, and why the battle lines between OpenAI and Anthropic are starting to become clearer. Watch now:</p><p><a href="https://www.youtube.com/watch?v=4YNHb0XNV1A" target="_blank" rel="noreferrer"></a></p><p>We also recorded a conversation with <strong>Angela Jiang</strong> , head of product for the Claude platform, and <strong>Katelyn Lesse</strong> , head of platform engineering. The full episode drops tomorrow on <em><a href="https://every.to/podcast" target="_blank" rel="noreferrer">AI&amp; I</a></em>—highlights below.— <strong><a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a></strong></p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><hr><h2 id="vibe-check-claude-managed-agents" tabindex="-1">Vibe Check: Claude Managed Agents <a class="header-anchor" href="#vibe-check-claude-managed-agents" aria-label="Permalink to &quot;Vibe Check: Claude Managed Agents&quot;">​</a></h2><h4 id="spiral-general-manager-marcus-moretti-uses-the-platform-s-new-features" tabindex="-1">Spiral general manager Marcus Moretti uses the platform’s new features <a class="header-anchor" href="#spiral-general-manager-marcus-moretti-uses-the-platform-s-new-features" aria-label="Permalink to &quot;Spiral general manager Marcus Moretti uses the platform’s new features&quot;">​</a></h4><p>Anthropic launched Claude Managed Agents in April, and since then, Every’s AI writing tool <strong><em><a href="https://writewithspiral.com/" target="_blank" rel="noreferrer">Spiral</a></em></strong> has used the platform to power its API and command line interface (CLI), which lets developers and other agents talk to Spiral outside the web app. Claude Managed Agents run on Anthropic’s servers, instead of us having to run them on our own.</p><p>We set up a new Managed Agent in an afternoon and <em><a href="https://every.to/context-window/the-missing-layer-in-ai-adoption#spiral-is-experimenting-with-agent-to-agent-workflows" target="_blank" rel="noreferrer">deployed it to power our API</a></em> the next day. We’ve incorporated two of the new features Anthropic announced yesterday (memory and multi-agent orchestration) and are deploying the third (outcomes) soon.</p><p><strong>Memory:</strong> Every’s editorial and social expertise—how to write a good X post, for example—lives in...</p><hr><p><strong>Become a <em><a href="https://every.to/subscribe" target="_blank" rel="noreferrer">paid subscriber to Every</a></em> to unlock this piece and learn about:</strong></p><ol><li>How Spiral is already using the new features announced this week</li><li>How Claude’s new “Dreaming” feature takes a page out of compound engineering</li><li>Why Anthropic says building a model-agnostic harness is a losing strategy</li></ol><p><a href="https://every.to/subscribe?source=post_button" target="_blank" rel="noreferrer">Subscribe</a></p><hr><p><em><a href="https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference" target="_blank" rel="noreferrer">Click here</a> to read the full post</em></p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr>',33)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
